transform_js:
const categories = [];
const values = [];
rawData.rows.forEach(r => {
  categories.push(r.category);
  values.push(r.value);
});
transformedData = { categories, values };

echarts_js:
option = {
  title: {
    text: 'Weekly Activity (Polar Bar)',
    left: 'center'
  },
  tooltip: {
    trigger: 'item'
  },
  polar: {
    radius: [30, '80%']
  },
  angleAxis: {
    type: 'category',
    data: transformedData.categories,
    startAngle: 90,
    axisLabel: {
      color: '#333',
      fontSize: 14
    }
  },
  radiusAxis: {
    max: 'dataMax'
  },
  series: [
    {
      type: 'bar',
      data: transformedData.values,
      coordinateSystem: 'polar',
      name: 'Activity',
      itemStyle: {
        color: function(params) {
          // 値の大きさではなく順番で色を変える
          return echarts.color.modifyHSL('#5470c6', params.dataIndex * 40);
        }
      }
    }
  ]
};
